SELECT T.ID, T.PORT_STORAGE_ID, T.CARGO_INFO_ID, T.WORK_DATE, T.CLASS_CODE, T.CLASS_NAME, T.PROCESS_DETAIL_CODE, T.PROCESS_DETAIL_NAME, T.STOREHOUSE_ID, T.STOREHOUSE_NAME, T.REGION_ID, T.REGION_NAME, T.MASS_ID, T.MASS_NAME, T.QUANTITY, T.TON, T.INOUT_TYPE, T.INOUT_STORAGE_CODE, T.INOUT_STORAGE_NAME, T.WORK_TICKET_ID, T.WORK_TICKET_DETAIL_ID, T.CARGO_TALLY_ID, T.CARGO_TALLY_DETAIL_ID, T.INOUT_DATE, T.COMPANY_ID, T.COMPANY_NAME, T.CLEAN_MASS_SIGN, T.CLEAN_MASS_BY, T.CLEAN_MASS_BY_NAME, T.CLEAN_MASS_TIME, T1.SHIP_NAME || '_' || T2.VOYAGE SHIP_NAME_VOYAGE, T1.CARGO_INFO_NO || '/' || T1.SHIP_NAME || '/' || T2.VOYAGE || '/' || T1.CARGO_OWNER_NAME || '/' || T1.CARGO_NAME || '/' || T1.TRADE_TYPE || '/' || T1.PACKING_NAME || '/' || T1.QUANTITY || '/' || T1.TON CARGO_INFO_LABEL FROM T_PRD_PORT_STORAGE_DETAIL T JOIN T_BUS_CARGO_INFO T1 ON T.CARGO_INFO_ID = T1.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T2 ON T1.SHIPVOYAGE_ITEM_ID = T2.ID
T.INOUT_STORAGE_CODE = '40'
AND T.WORK_DATE = #{workDate, jdbcType=TIMESTAMP}
AND T.CLASS_CODE = #{classCode, jdbcType=VARCHAR}
AND T.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND T.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND T.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
AND T.REGION_ID = #{regionId, jdbcType=BIGINT}
AND T.MASS_ID = #{massId, jdbcType=BIGINT}

SELECT T1.COMPANY_ID, T1.COMPANY_NAME, T1.CARGO_INFO_ID, T1.STOREHOUSE_ID, T1.STOREHOUSE_NAME, T1.REGION_ID, T1.REGION_NAME, T1.MASS_ID, T1.MASS_NAME, T1.QUANTITY, T1.TON, T.SHIP_NAME || '_' || T3.VOYAGE SHIP_NAME_VOYAGE, T.CARGO_INFO_NO || '/' || T.SHIP_NAME || '/' || T3.VOYAGE || '/' || T.CARGO_OWNER_NAME || '/' || T.CARGO_NAME || '/' || T.TRADE_TYPE || '/' || T.PACKING_NAME || '/' || T.QUANTITY || '/' || T.TON CARGO_INFO_LABEL FROM T_PRD_PORT_STORAGE T1 JOIN T_BUS_CARGO_INFO T ON T1.CARGO_INFO_ID = T.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T3 ON T.SHIPVOYAGE_ITEM_ID = T3.ID
AND T1.COMPANY_ID = #{companyId, jdbcType=BIGINT}
and T.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
and T3.ID=#{shipvoyageItemId}
AND T1.CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
AND T1.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
AND T1.REGION_ID = #{regionId, jdbcType=BIGINT}
AND T1.MASS_ID = #{massId, jdbcType=BIGINT}

SELECT T1.COMPANY_ID, T1.COMPANY_NAME, T1.CARGO_INFO_ID, T1.STOREHOUSE_ID, T1.STOREHOUSE_NAME, T1.REGION_ID, T1.REGION_NAME, T1.MASS_ID, T1.MASS_NAME, T1.QUANTITY, T1.TON, T.SHIP_NAME || '_' || T3.VOYAGE SHIP_NAME_VOYAGE, T.QUANTITY || '/' || T.TON || '/' || T.TRADE_TYPE || '/' || T.PACKING_NAME || '/' || T.CARGO_NAME || '/' || T.CARGO_AGENT_NAME || '/' || T.CARGO_OWNER_NAME || '/' || T.CARGO_INFO_NO CARGO_INFO_LABEL FROM T_PRD_PORT_STORAGE T1 JOIN T_BUS_CARGO_INFO T ON T1.CARGO_INFO_ID = T.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T3 ON T.SHIPVOYAGE_ITEM_ID = T3.ID
AND T1.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND T1.CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
AND T1.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
AND T1.REGION_ID = #{regionId, jdbcType=BIGINT}
AND T1.MASS_ID = #{massId, jdbcType=BIGINT}
